diagram.chart:
graph TD;
    A[UserPromptNode<br/>用户输入] --> B[SystemPromptFunc<br/>系统提示生成];
    B --> C[ModelRequestNode<br/>调用 LLM];
    C --> D[模型响应];
    D --> E{包含工具调用?};
    E -->|是| F[CallToolsNode<br/>执行工具];
    F --> G[工具结果];
    G --> C;
    E -->|否且输出匹配类型| H[End<br/>返回结果];
    E -->|否| C;
    style H fill:#90EE90;
    style C fill:#FFB6C1;
    style F fill:#ADD8E6;
